<template>


	<view class="wrap">

		<!-- 	<u-navbar :custom-back="backpage">
			<u-search v-model="keyword" placeholder="请输入订单号" height="56" @search="search" @custom="search">
			</u-search>

		</u-navbar> -->

		<scroll-view scroll-y style="height: 100%;width: 100%;background-color: #f5f7fa;" @scrolltolower="reachBottom">
			<view style=" margin-top: 20rpx; padding: 0 20rpx;">
				<u-search placeholder="请输入关键字" v-model="keyword" @custom="search" @search="search"></u-search>
			</view>
			<view class="order" v-for="(item,index) in list" :key="index" @click="onGoods(item.goods_id,1,item)">

				<view class="item">
					<view class="good-type" :style="{
							backgroundColor: 	item.is_goods_type?'#12bd4380':item.goods_type==1?'#ff450080':'#07b4ff80',
						}">
						{{item.is_goods_type?'人工代充':item.goods_type==1?'卡密兑换':'自动发货'}}
					</view>
					<image class="show-img" :src="item.goods_img" mode="aspectFit"></image>
					<view class="content">
						<text class="title">{{item.goods_name}}</text>
						<view class="time">{{$util.timeFormat(item.create_time,"yyyy-mm-dd hh:MM:ss")}}</view>
						<view class="other">
							<view class="price">
								<text class="now">¥{{item.price}}</text>

								<text class="market">¥{{item.price1}}</text>
								<text class="icon" :class="item.price_type == 1? 'up':'down'"></text>
								<text :class="item.price_type == 1? 'up':'down'"
									class="change">¥{{item.pricecha}}</text>

							</view>
							<view class="btn" :class="item.status == 2?'stop':''">
								{{item.status == 2?'暂停':'销售'}}
							</view>
						</view>
					</view>
				</view>






			</view>
			<u-loadmore :status="loadStatus" icon-type="circle" v-if="list.length >0 && loaded" />
			<u-empty v-if="loaded &&  list.length == 0"></u-empty>


		</scroll-view>


	</view>



</template>

<script>
	export default {
		data() {
			return {

				keyword: '',
				sys: this.$util.sys(),
				limit: 10,


				loadStatus: 'loadmore',
				page: 1,

				count: 0,
				list: [],
				loaded: false,
				statusColor: [{
						color: '#999'
					},
					{
						color: '#f7b24b'
					},
					{
						color: '#ff8507'
					},
					{
						color: '#90dd90'
					},
					{
						color: '#ccc'
					},
					{
						color: '#f00'
					}
				],

				current: 0,
				swiperCurrent: 0,

				dx: 0,
			};
		},
		onLoad(e) {


			if (e.status) {
				this.swiperCurrent = e.status
				this.current = e.status

			}

			this.loadData(this.swiperCurrent);
		},
		methods: {
			backpage() {
				this.$util.back()
			},
			paste(val) {

				uni.setClipboardData({
					data: val,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			reachBottom() {


				setTimeout(() => {
					this.loadData(this.current);
				}, 200);

			},
			search() {
				this.list = []
				this.page = 1
				this.loaded = false
				this.current = 0
				this.swiperCurrent = 0
				this.loadData(0);

			},
			// 页面数据
			async loadData(idx) {


				await this.$u.api.pricelog({

						keyword: this.keyword,
						page: this.page,
						limit: this.limit,
					})
					.then(res => {
						if (res.length == 0) {
							this.loadStatus = 'nomore'
						} else {
							if (this.list.length > 0) {
								this.list = this.list.concat(res)

							} else {
								this.list = res

							}

							if (res.length < this.limit) {
								this.loadStatus = 'nomore'
							} else {
								this.loadStatus = 'loadmore'
							}


							this.page++
						}
					}).catch(res => {})

				this.loaded = true;
				//loaded新字段用于表示数据加载完毕，如果为空可以显示空白页

				// console.log(item	);
			},
			// 总价
			totalPrice(item) {
				let price = 0;
				item.map(val => {
					price += parseFloat(val.price);
				});
				return price.toFixed(2);
			},
			// 总件数
			totalNum(item) {
				let num = 0;
				item.map(val => {
					num += val.number;
				});
				return num;
			},
			// tab栏切换
			change(index) {
				this.swiperCurrent = index;
				this.loadData(index);
			},
			transition({
				detail: {
					dx
				}
			}) {

				this.$refs.tabs.setDx(dx);
			},
			animationfinish({
				detail: {
					current
				}
			}) {

				this.$refs.tabs.setFinishCurrent(current);
				this.swiperCurrent = current;
				this.current = current;
				if (!this.orderList[current].loaded) {
					this.loadData(current)
				}
			},
		}
	};
</script>

